module RefModule (  
    input [63:0] data_in,  
    input [63:0] key,  
    input clk,  
    output reg [63:0] data_out  
);  
    integer obf_i;  
    always @(posedge clk) begin  
        for (obf_i = 0; obf_i < 8; obf_i = obf_i + 1) begin  
            data_out[obf_i*8 +: 8] <= data_in[obf_i*8 +: 8] ^ key[obf_i*8 +: 8];  
        end  
    end  
endmodule
